"""Records an mp4 file using Jibo's Media Service"""
import os
import json
from glob import glob
from http_recorder import HttpRecorder


class VideoRecorder(HttpRecorder):
    """VideoRecorder Class"""

    def __init__(self, name, robot, output_dir, root, ui_queue, add_video):
        self.__url_start = 'http://' + str(robot) + ':8486/media/recording/start'
        self.__url_stop = 'http://' + str(robot) + ':8486/media/recording/control?id=0&cmd=stop'
        self.__robot_directory = '/opt/jibo/Recordings'

        # Create request data for START
        data = {}
        data['audioRec'] = {}
        data['audioRec']['volume'] = 1
        data['audioRec']['source'] = 'MediaIn'
        data['meta'] = {}
        if add_video:
            data['videoRec'] = {}
            data['videoRec']['height'] = 360
            data['videoRec']['width'] = 640
            data['videoRec']['camera'] = 1
            data['videoRec']['flip'] = 'horizontal-flip'
        data = json.dumps(data)
        self.__data_start = data

        # Create request data for STOP
        self.__data_stop = json.dumps({})

        # Call HttpRecorder parent
        HttpRecorder.__init__(self, name, self.__url_start, self.__url_stop,
                              self.__data_start, self.__data_stop,
                              robot, output_dir, root, ui_queue)

    def stop(self):
        """Calls parent stop; Grabs files on robot, rsync to local, deletes files on robot"""
        super(VideoRecorder, self).stop()

        if self.has_stopped:
            # Get files via rsync
            os.system('rsync -r -v --progress -e ssh root@' +
                      self.robot + ':' + self.__robot_directory + ' ' + self.directory)
            self.update_ui('Done video file transfer', 'dark green')

            # Delete files on robot
            files = self.sftp.listdir(path=self.__robot_directory)
            for filename in files:
                self.sftp.remove(os.path.join(self.__robot_directory, filename))

            # Update UI
            self.update_ui('Downloaded Files', 'dark green')
